#define _GNU_SOURCE

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <net/if.h>
#include <arpa/inet.h>
#include <bpf/libbpf.h>
#include <bpf/bpf.h>
#include <sys/stat.h>
#include <time.h>
// This header is generated by bpftool based on the BPF program and contains skeleton definitions
#include "xdp_ips.skel.h"

// Must exactly match the kernel struct
struct block_info {
    __u64 expiry;
    __u32 reason;
};

static volatile bool exiting = false;

static void sig_handler(int sig) {
    exiting = true;
}

// Helper to format IP addresses
void format_ip(__u32 ip, char *buf) {
    struct in_addr addr;
    addr.s_addr = ip;
    inet_ntop(AF_INET, &addr, buf, INET_ADDRSTRLEN);
}

// Week 5 Milestone: Monitoring and Metrics
void poll_blocklist(int map_fd) {
    __u32 key = 0, next_key;
    struct block_info value; // Using the new struct
    char ip_str[INET_ADDRSTRLEN];
    int active_blocks = 0;

    time_t now_wall = time(NULL);
    struct tm *tm_info = localtime(&now_wall);
    char time_buf[26];
    strftime(time_buf, 26, "%Y-%m-%d %H:%M:%S", tm_info);

    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    __u64 now_ns = ts.tv_sec * 1000000000ULL + ts.tv_nsec;

    printf("\033[2J\033[H");
    printf("=============================================================\n");
    printf(" Vasi: XDP Intrusion Prevention System | %s\n", time_buf);
    printf("=============================================================\n");
    printf(" %-20s | %s\n", "Source IP Address", "Status");
    printf("-------------------------------------------------------------\n");

    while (bpf_map_get_next_key(map_fd, &key, &next_key) == 0) {
        if (bpf_map_lookup_elem(map_fd, &next_key, &value) == 0) {
            
            if (now_ns > value.expiry) {
                // 1. Delete the IP from the BPF map
                bpf_map_delete_elem(map_fd, &next_key);

                // 2. Format the IP address into a readable string
                format_ip(next_key, ip_str);

                // 3. Inject the unblock log directly into the kernel's trace_pipe
                FILE *trace_fd = fopen("/sys/kernel/debug/tracing/trace_marker", "w");
                if (trace_fd) {
                    fprintf(trace_fd, "IP %s unblocked. 30s block window expired.\n", ip_str);
                    fclose(trace_fd);
                }
            } else {
                format_ip(next_key, ip_str);
                
                // Translate the reason integer into a string
                char *reason_str = "UNKNOWN";
                if (value.reason == 1) reason_str = "SYN";
                else if (value.reason == 2) reason_str = "ICMP";
                else if (value.reason == 3) reason_str = "UDP";
                else if (value.reason == 4) reason_str = "MANUAL";

                printf(" %-20s | \033[31mBLOCKED [%s]\033[0m\n", ip_str, reason_str);
                active_blocks++;
            }
        }
        key = next_key;
    }
    
    if (active_blocks == 0) {
        printf(" %-20s | \033[32mSECURE\033[0m\n", "No active threats");
    }
    printf("=============================================================\n");
    printf(" Active Mitigations: %d\n", active_blocks);
    printf(" Press Ctrl+C to detach IPS and exit.\n");
    
    fflush(stdout); 
}

int main(int argc, char **argv) {
    struct xdp_ips_bpf *skel;
    int err = 0, ifindex;

    if (argc < 2) {
        fprintf(stderr, "Usage: %s <ifname>\n", argv[0]);
        return 1;
    }

    ifindex = if_nametoindex(argv[1]);
    if (!ifindex) {
        fprintf(stderr, "Failed to get ifindex of %s\n", argv[1]);
        return 1;
    }

    // Week 4 Milestone: User-Space Management
    skel = xdp_ips_bpf__open_and_load();
    if (!skel) {
        fprintf(stderr, "Failed to open and load BPF skeleton\n");
        return 1;
    }

    skel->links.xdp_ips_main = bpf_program__attach_xdp(skel->progs.xdp_ips_main, ifindex);
    if (!skel->links.xdp_ips_main) {
        fprintf(stderr, "Failed to attach XDP program\n");
        err = -1;
        goto cleanup;
    }

    signal(SIGINT, sig_handler);
    signal(SIGTERM, sig_handler);

    printf("IPS loaded on %s. Enforcing thresholds (SYN:100/s, ICMP:50/s, UDP:200/s).\n", argv[1]);

    int blocklist_fd = bpf_map__fd(skel->maps.blocklist);

    // Week 4-5 Milestone: Dynamic Manual Blocklist
    time_t last_mod_time = 0;
    struct stat file_stat;

    // Monitoring loop
    while (!exiting) {
        // Check if blacklist.txt exists and/or has been modified
        if (stat("blacklist.txt", &file_stat) == 0) {
            if (file_stat.st_mtime > last_mod_time) {
                FILE *fp = fopen("blacklist.txt", "r");
                if (fp) {
                    char line[64];
                    while (fgets(line, sizeof(line), fp)) {
                        // Strip newline characters from the file read
                        line[strcspn(line, "\r\n")] = 0;
                        __u32 manual_ip;
                        // Convert the string IP to network byte order
                        if (inet_pton(AF_INET, line, &manual_ip) == 1) {
                            struct block_info static_block = {
                                .expiry = 0xFFFFFFFFFFFFFFFFULL, // Max 64-bit int (Never expires)
                                .reason = 4                      // Code for Manual Block
                            };
                            bpf_map_update_elem(blocklist_fd, &manual_ip, &static_block, BPF_ANY);

                            // NEW: Log the manual block injection to the kernel trace pipe
                            FILE *trace_fd = fopen("/sys/kernel/debug/tracing/trace_marker", "w");
                            if (trace_fd) {
                                fprintf(trace_fd, "IP %s is MANUALLY BLOCKED by blacklist.txt.\n", line);
                                fclose(trace_fd);
                            }
                        }
                    }
                    fclose(fp);
                    last_mod_time = file_stat.st_mtime;
                }
            }
        }

        poll_blocklist(blocklist_fd);
        sleep(1);
    }

cleanup:
    xdp_ips_bpf__destroy(skel);
    printf("\nIPS detached successfully.\n");
    return err < 0 ? -err : 0;
}